#!/usr/bin/env node
/**
 * Docusaurus imports src/data/skills.json at build time. The real catalog is
 * generated by scripts/extract-skills.py (see CI). For local dev, ensure a
 * valid JSON file exists so webpack can resolve the module.
 */
import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const websiteRoot = path.join(__dirname, "..");
const dir = path.join(websiteRoot, "src", "data");
const file = path.join(dir, "skills.json");

fs.mkdirSync(dir, { recursive: true });
if (!fs.existsSync(file)) {
  fs.writeFileSync(file, "[]\n", "utf8");
  process.stderr.write(`Created placeholder ${path.relative(websiteRoot, file)} (run python3 scripts/extract-skills.py for full data)\n`);
}
